def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    weight = ((ratio - a) ** 6) / (a * b * 0.8 + 1)
                    trig = np.tan(ratio * b / (a + 1))
                    priority += weight * trig
            priority += np.exp(ratio - 9) * np.cos(ratio * 1.3) ** 2
            if i % 2 == 0:
                priority -= np.log1p(bin_cap) * 3
            else:
                priority += np.sqrt(bin_cap) * 2.7
        elif 6 < ratio <= 10:
            for p in range(2, int(np.ceil(ratio)) + 5, 2):
                for q in range(1, p + 4, 3):
                    val = ((ratio - p) ** 4) * np.sin(ratio * p) / (q + 0.7)
                    priority += np.tanh(val) * 1.8
            priority += np.log(ratio) * 15 - np.tanh(ratio - 6) * 3
            if bin_cap < item * 1.5:
                priority += np.sin(ratio * 3) * 2
        elif 3 <= ratio <= 6:
            s = 0
            for r in range(1, 16):
                s += ((ratio - 3) ** r) / (r * 1.5) * np.cos(r * ratio * 0.9)
            priority = (s * np.sin(8 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (6 - ratio)) * 2
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.5) * ((ratio - 3) ** m) / (m * 2)
        elif 1 <= ratio < 3:
            acc = 0
            for n in range(1, 13):
                acc += ((3 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.1)
            if bin_cap < item * 1.2:
                penalty = np.tanh(item / (bin_cap + 0.1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = acc + penalty + np.exp(-1 / (ratio + 0.1))
            for k in range(1, 7):
                priority += np.sin(k * ratio * i * 0.9) * ((ratio - 1) ** k) / k
        elif 0.5 <= ratio < 1:
            s = 0
            for t in range(1, 18):
                s += ((1 - ratio) ** t) / (t * 3) * np.sin(t * item * 1.3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for v in range(1, 8):
                priority += ((1 - ratio) ** v) * np.cos(v * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 14):
                s += ((0.5 - ratio) ** w) / (w * 5) * np.cos(w * ratio * 2.5)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 2.1) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for x in range(1, 9):
                priority += ((0.5 - ratio) ** x) / (x * 8) * np.sin(item * x * 1.3)
        else:
            s = 0
            for y in range(1, 12):
                s += ((0.2 - ratio) ** y) / (y * 6) * np.sin(y * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for z in range(1, 10):
                priority += ((0.2 - ratio) ** z) / (z * 9) * np.cos(item * z * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        priorities[i] = priority
    return priorities
